class Coupon {
  constructor(code) {
    this.code = code;
    this.isUsed = false;
    this.validUntil; //date
  }

  validate() {
    return this.code && !this.isUsed;
  };

  markAsUsed () {
    if (this.validate())
      this.isUsed = true;

    return this;
  };
}

